// archetype-index.ts — the real player→archetype taxonomy (your Archetype Family Scorer).
// Generated from archetype-family-index-combined-436.csv + the family_score_vector batches.
// 435 players · 8 families · 45 scoring profiles · 120 with score vectors.
// Keys are diacritic-folded (Jokić→jokic) so accented index names match the ASCII sim roster.

export interface ArchetypeRecord {
  player: string; label: string; family: string; secondary: string;
  profile: string; system: string; coverage: string; cap: number;
  vector?: Record<string, number>;
}

/** Fold diacritics + strip to alnum+space so "Nikola Jokić" and "Nikola Jokic" collide. */
export function normName(n: string): string {
  return n.normalize("NFKD").replace(/[\u0300-\u036f]/g, "")
    .toLowerCase().replace(/[.\x27]/g, "").replace(/[^a-z0-9 ]/g, "").replace(/\s+/g, " ").trim();
}

