export function profileFamily(profile: string): string { return PROFILE_FAMILY[profile] ?? ""; }
export function prettyProfile(p: string): string { return p ? p.replace(/_/g, " ").replace(/\b\w/g, (c) => c.toUpperCase()) : ""; }
export function prettyFamily(f: string): string { return f ? f.charAt(0).toUpperCase() + f.slice(1) : ""; }
